import{_ as t,o as n,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"22. Letter Of Appointment","description":"","frontmatter":{"title":"22. Letter Of Appointment","eba":"Nurses and Midwives 2024-2028","topics":["employment"]},"headers":[],"relativePath":"ebas/nurses-midwives/employment-types/22-letter-of-appointment.md","filePath":"ebas/nurses-midwives/employment-types/22-letter-of-appointment.md"}'),i={name:"ebas/nurses-midwives/employment-types/22-letter-of-appointment.md"};function r(p,e,s,m,l,d){return n(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_22-letter-of-appointment" tabindex="-1">22. Letter Of Appointment <a class="header-anchor" href="#_22-letter-of-appointment" aria-label="Permalink to &quot;22. Letter Of Appointment&quot;">​</a></h1><p><strong>22.1</strong> On commencement of employment, the Employer will provide each Employee with a letter of appointment containing the information set out in <a href="/eba/ebas/nurses-midwives/appendices/03-information-required-for-letter-of-appointment.html">Appendix 3</a>.</p><p><strong>22.2</strong> Where the appointment is varied, the variation shall be recorded in writing and an updated Letter of Appointment or copy of the variation provided to the Employee within 28 days of the variation.</p><p><strong>22.3</strong> Where an updated Letter of Appointment or variation can be generated through an Employee kiosk or similar and is available to the Employee, this will satisfy the requirements of clause 22.2.</p><p>Plain language terms: offer letter, appointment letter, employment contract.</p>',5)])])}const h=t(i,[["render",r]]);export{c as __pageData,h as default};
